import math
class Solution:
    def sum_square_root(self, nums: list[int]) -> float:
        return math.sqrt(sum(i*i for i in nums))
if __name__ == '__main__':
    t = int(input())
    for _ in range(t):
        n = int(input())
        nums = list(map(int,input().split()))
