#include <iostream>
#include <cmath>
#include <vector>
using namespace std;
class Solution {
public:
    vector<double> sumSquareRoot(vector<int>& nums) {
        double sum = 0;
        for(int i = 0; i < nums.size(); i++) sum += nums[i]*nums[i];
        return {sqrt(sum)};
    }
};
int main() {
    int t;
    cin >> t;
    while(t--)
    {
        int n;
        cin >> n;
        vector<int> nums(n);
        for(int i = 0; i < n; i++)
        {
            cin >> nums[i];
        }
        if(Solution().sumSquareRoot(nums)[0] == (double) floor(Solution().sumSquareRoot(nums)[0]))
            cout << (int)Solution().sumSquareRoot(nums)[0] << endl;
        else
            cout << Solution().sumSquareRoot(nums)[0] << endl;
    }
    return 0;
}
